9	// Fail closed: reflecting any origin (origin: true) together with
10	// credentials: true is effectively open CORS. Only default to permissive
11	// reflection for local development; in any other environment an explicit
12	// CORS_ORIGINS allowlist is required, otherwise no cross-origin is allowed.
13	const corsOrigins = process.env.CORS_ORIGINS
