1	/**
2	 * https://docs.cloud.google.com/run/docs/authenticating/service-to-service
3	 */
4	const { GoogleAuth } = require("google-auth-library");
5	
6	const auth = new GoogleAuth();
7	
8	// Cache one IdTokenClient per target audience. Creating the client and the
9	// underlying ID token are both expensive (metadata-server round trips); the
10	// client also caches/refreshes the ~1h token internally, so reusing it avoids
11	// re-fetching a fresh token on every single proxied request.
12	const idTokenClients = new Map();
13	
14	function getIdTokenClient(targetAudience) {
15	  let clientPromise = idTokenClients.get(targetAudience);
16	  if (!clientPromise) {
17	    clientPromise = auth.getIdTokenClient(targetAudience).catch((err) => {
18	      // Don't cache a rejected client — allow the next request to retry.
19	      idTokenClients.delete(targetAudience);
20	      throw err;
21	    });
22	    idTokenClients.set(targetAudience, clientPromise);
23	  }
24	  return clientPromise;
25	}
26	
27	function isLocalHttpBackend(url) {
28	  try {
29	    const u = new URL(url);
30	    return (
31	      u.protocol === "http:" &&
32	      (u.hostname === "localhost" || u.hostname === "127.0.0.1")
33	    );
34	  } catch {
35	    return false;
36	  }
37	}
38	
39	/**
40	 * Cloud Run requires an OIDC identity token in Authorization.
41	 * The app JWT is forwarded in X-User-Authorization so backends can keep using req.headers.authorization.
42	 * Local HTTP backends skip OIDC; the browser's Authorization header is forwarded unchanged.
43	 */
44	async function attachInvokingIdentityHeaders(backendUrl, req) {
45	  if (isLocalHttpBackend(backendUrl)) {
46	    return;
47	  }
48	  const targetAudience = backendUrl.replace(/\/$/, "");
49	  const client = await getIdTokenClient(targetAudience);
50	  const idToken = await client.idTokenProvider.fetchIdToken(targetAudience);
51	  const userAuth = req.headers.authorization;
52	  req.headers.authorization = `Bearer ${idToken}`;
53	  if (userAuth) {
54	    req.headers["x-user-authorization"] = userAuth;
55	  }
56	}
57	
58	module.exports = { attachInvokingIdentityHeaders };
