1	const crypto = require("crypto");
2	
3	const API_KEY_HEADER = "x-api-key";
4	const DEFAULT_JWT_TTL = "1h";
5	
6	function hashApiKey(apiKey) {
7	  return crypto.createHash("sha256").update(apiKey, "utf8").digest("hex");
8	}
9	
10	function safeEqual(a, b) {
11	  const left = Buffer.from(String(a || ""), "utf8");
12	  const right = Buffer.from(String(b || ""), "utf8");
13	  return left.length === right.length && crypto.timingSafeEqual(left, right);
14	}
15	
16	function parseDurationSeconds(value = DEFAULT_JWT_TTL) {
17	  const match = String(value).trim().match(/^(\d+)\s*(s|m|h|d)?$/i);
18	  if (!match) {
19	    throw new Error(`Invalid API_KEY_JWT_TTL: ${value}`);
20	  }
21	
22	  const amount = Number(match[1]);
23	  const unit = (match[2] || "s").toLowerCase();
24	  const multipliers = { s: 1, m: 60, h: 60 * 60, d: 24 * 60 * 60 };
25	  return amount * multipliers[unit];
26	}
27	
28	function base64url(input) {
29	  const buffer = Buffer.isBuffer(input) ? input : Buffer.from(JSON.stringify(input));
30	  return buffer
31	    .toString("base64")
32	    .replace(/=/g, "")
33	    .replace(/\+/g, "-")
34	    .replace(/\//g, "_");
35	}
36	
37	function parseApiKeys(raw = process.env.DESIGNFLOW_API_KEYS) {
38	  if (!raw || !raw.trim()) {
39	    return [];
40	  }
41	
42	  let parsed;
43	  try {
44	    parsed = JSON.parse(raw);
45	  } catch (err) {
46	    throw new Error("DESIGNFLOW_API_KEYS must be valid JSON");
47	  }
48	
49	  const entries = Array.isArray(parsed) ? parsed : [parsed];
50	  return entries.map((entry, index) => {
51	    const keyHash = entry.keyHash || (entry.key ? hashApiKey(entry.key) : null);
52	    const claims = entry.claims || {};
53	
54	    if (!keyHash) {
55	      throw new Error(`DESIGNFLOW_API_KEYS[${index}] is missing keyHash`);
56	    }
57	    if (!claims.user_id || !claims.email || !claims.role) {
58	      throw new Error(`DESIGNFLOW_API_KEYS[${index}] claims require user_id, email, and role`);
59	    }
60	
61	    return {
62	      name: entry.name || `api-key-${index + 1}`,
63	      keyHash,
64	      claims,
65	    };
66	  });
67	}
68	
69	// Parse + per-entry SHA-256 hashing of DESIGNFLOW_API_KEYS is the same on every
70	// request, so memoize it. Only the incoming key's hash + safeEqual run per call.
71	let cachedApiKeys = null;
72	function getApiKeys() {
73	  if (cachedApiKeys === null) {
74	    cachedApiKeys = parseApiKeys();
75	  }
76	  return cachedApiKeys;
77	}
78	
79	function findApiKeyEntry(apiKey, entries = getApiKeys()) {
80	  const incomingHash = hashApiKey(apiKey);
81	  return entries.find((entry) => safeEqual(incomingHash, entry.keyHash));
82	}
83	
84	function signInternalJwt(claims, options = {}) {
85	  const privateKey = options.privateKey || process.env.JWT_PRIVATE_KEY;
86	  if (!privateKey) {
87	    throw new Error("JWT_PRIVATE_KEY is required for API key authentication");
88	  }
89	
90	  const now = Math.floor(Date.now() / 1000);
91	  const ttlSeconds = parseDurationSeconds(options.ttl || process.env.API_KEY_JWT_TTL || DEFAULT_JWT_TTL);
92	  const header = { alg: "RS256", typ: "JWT" };
93	  const payload = {
94	    ...claims,
95	    iat: now,
96	    exp: now + ttlSeconds,
97	    auth_type: "api_key",
98	  };
99	
100	  const signingInput = `${base64url(header)}.${base64url(payload)}`;
101	  const signer = crypto.createSign("RSA-SHA256");
102	  signer.update(signingInput);
103	  signer.end();
104	  const signature = signer.sign(privateKey);
105	
106	  return `${signingInput}.${base64url(signature)}`;
107	}
108	
109	function apiKeyAuthMiddleware(req, res, next) {
110	  const apiKey = req.headers[API_KEY_HEADER];
111	  if (!apiKey) {
112	    return next();
113	  }
114	
115	  let entry;
116	  try {
117	    entry = findApiKeyEntry(apiKey);
118	  } catch (err) {
119	    console.error("[BFF API key config error]", err.message);
120	    return res.status(500).json({ error: "API key authentication is misconfigured" });
121	  }
122	
123	  if (!entry) {
124	    return res.status(401).json({ error: "Invalid API key" });
125	  }
126	
127	  try {
128	    req.headers.authorization = signInternalJwt({
129	      ...entry.claims,
130	      api_key_name: entry.name,
131	    });
132	    delete req.headers[API_KEY_HEADER];
133	    return next();
134	  } catch (err) {
135	    console.error("[BFF API key auth error]", err.message);
136	    return res.status(500).json({ error: "API key authentication failed" });
137	  }
138	}
139	
140	module.exports = {
141	  apiKeyAuthMiddleware,
142	  findApiKeyEntry,
143	  hashApiKey,
144	  parseApiKeys,
145	  signInternalJwt,
146	};
