1	const express = require("express");
2	const httpProxy = require("http-proxy");
3	const { SERVICE_MAP } = require("../src/serviceMap");
4	const { attachInvokingIdentityHeaders } = require("../src/backendProxy");
5	const { apiKeyAuthMiddleware } = require("../src/apiKeyAuth");
6	
7	const router = express.Router();
8	
9	// Timeouts so a slow/hung backend cannot hold a BFF connection open forever
10	// and exhaust sockets under load. timeout = incoming socket, proxyTimeout = upstream.
11	const PROXY_TIMEOUT_MS = Number(process.env.BFF_PROXY_TIMEOUT_MS) || 30000;
12	const proxy = httpProxy.createProxyServer({
13	  xfwd: true,
14	  proxyTimeout: PROXY_TIMEOUT_MS,
15	  timeout: PROXY_TIMEOUT_MS + 1000,
16	});
17	
18	proxy.on("error", (err, req, res) => {
19	  console.error("[BFF proxy error]", err?.message || err);
20	  if (res && !res.headersSent && typeof res.writeHead === "function") {
21	    res.writeHead(502, { "Content-Type": "application/json" });
22	    res.end(JSON.stringify({ error: "Bad gateway" }));
23	  }
24	});
25	
26	router.use(apiKeyAuthMiddleware);
27	
28	/**
29	 * /api/<service>/<backend-path>
30	 * Example: /api/core/getAllItems, /api/item_master/lib/getAllitems
31	 */
32	router.use(async (req, res) => {
33	  const pathname = req.path.replace(/^\//, "");
34	  const segments = pathname.split("/").filter(Boolean);
35	  const service = segments[0];
36	  const backendPath = segments.slice(1).join("/");
37	
38	  const backendUrl = SERVICE_MAP[service];
39	  if (!backendUrl) {
40	    return res.status(404).json({
41	      error: `Unknown backend service: ${service}`,
42	    });
43	  }
44	  if (!backendPath) {
45	    return res.status(404).json({ error: "Missing backend path" });
46	  }
47	
48	  const qIdx = req.url.indexOf("?");
49	  const search = qIdx !== -1 ? req.url.substring(qIdx) : "";
50	
51	  try {
52	    await attachInvokingIdentityHeaders(backendUrl, req);
53	    req.url = `/${backendPath}${search}`;
54	
55	    proxy.web(req, res, {
56	      target: backendUrl.replace(/\/$/, ""),
57	      changeOrigin: true,
58	    });
59	  } catch (err) {
60	    // The only awaited call here is attachInvokingIdentityHeaders (OIDC/identity
61	    // failures). proxy.web errors are reported via the proxy.on("error") handler,
62	    // not here, so there is no axios-style err.response to passthrough.
63	    console.error(`[BFF ERROR] ${service} ${req.method} ${req.originalUrl}`, err.message);
64	    if (!res.headersSent) {
65	      res.status(500).send({ error: "Backend request failed" });
66	    }
67	  }
68	});
69	
70	module.exports = router;
